# 4. EXECUTION
# ==========================================
if __name__ == "__main__":
    MAX_EPOCHS = 150

    print("Loading Data & Creating Splits...")
    dfV = pd.read_csv("HELMET_Triangular_Targets_with_V.csv")
    patientArray = create_patient_objects(dfV)
    train_patients, temp_patients = train_test_split(patientArray, test_size=0.30, random_state=42)
    val_patients, test_patients = train_test_split(temp_patients, test_size=0.50, random_state=42)
    train_act, train_triv = generate_maps(train_patients)

    print("\n--- 1. Training MSE Model ---")
    p_mse = optuna.load_study(study_name='new_mse_study', storage='sqlite:///optuna_new_mse_study.db').best_params
    m_mse = DirectRewardNet(input_dim=46, T=3, hidden_dim=p_mse['hidden_dim']).to(device)
    train_standard_regression(m_mse, optim.AdamW(m_mse.parameters(), lr=p_mse['lr'],
                                                 weight_decay=p_mse.get('weight_decay', 1e-4)), nn.MSELoss(),
                              train_patients, val_patients, train_act, train_triv, p_mse['batch_size'],
                              p_mse['actionable_ratio'], p_mse['scale_factor'], MAX_EPOCHS, 'final_mse.pth')

    print("\n--- 2. Training Huber Model ---")
    p_hub = optuna.load_study(study_name='new_huber_study', storage='sqlite:///optuna_new_huber_study.db').best_params
    m_hub = DirectRewardNet(input_dim=46, T=3, hidden_dim=p_hub['hidden_dim']).to(device)
    train_standard_regression(m_hub, optim.AdamW(m_hub.parameters(), lr=p_hub['lr'],
                                                 weight_decay=p_hub.get('weight_decay', 1e-4)),
                              nn.HuberLoss(delta=p_hub.get('delta', 1.0)), train_patients, val_patients, train_act,
                              train_triv, p_hub['batch_size'], p_hub['actionable_ratio'], p_hub['scale_factor'],
                              MAX_EPOCHS, 'final_huber.pth')

    print("\n--- 3. Training Classifier Model ---")
    p_cls = optuna.load_study(study_name='new_classifier_study',
                              storage='sqlite:///optuna_new_classifier_study.db').best_params
    m_cls = ClassifierNet(input_dim=46, hidden_dim=p_cls['hidden_dim']).to(device)
    c_weights = calculate_class_weights(train_patients)
    train_classifier(m_cls, optim.AdamW(m_cls.parameters(), lr=p_cls['lr'], weight_decay=p_cls['weight_decay']),
                     nn.CrossEntropyLoss(weight=c_weights.to(device)), train_patients, val_patients, train_act,
                     train_triv, p_cls['batch_size'], p_cls['actionable_ratio'], MAX_EPOCHS, 'final_classifier.pth')

    print("\n--- 4. Training SPO+ Model ---")
    p_spo = optuna.load_study(study_name='new_spo_dfl_study', storage='sqlite:///optuna_new_spo_dfl.db').best_params
    m_spo = DirectRewardNet(input_dim=46, T=3, hidden_dim=p_spo['hidden_dim']).to(device)
    train_spo_plus(m_spo, optim.AdamW(m_spo.parameters(), lr=p_spo['lr'], weight_decay=p_spo.get('weight_decay', 1e-4)),
                   train_patients, val_patients, train_act, train_triv, p_spo['batch_size'],
                   p_spo['train_actionable_ratio'], p_spo['scale_factor'], MAX_EPOCHS, 'final_spo.pth')

    print("\nAll final models trained! Proceed to new_evaluate_test_set.py")
